     873: static CURLcode dupset(struct Curl_easy *dst, struct Curl_easy *src)
     874: {
     875:   CURLcode result = CURLE_OK;
     876:   enum dupstring i;
     877:   enum dupblob j;
     878: 
     879:   /* Copy src->set into dst->set first, then deal with the strings
     880:      afterwards */
     881:   dst->set = src->set;
     882: #if !defined(CURL_DISABLE_MIME) || !defined(CURL_DISABLE_FORM_API)
     883:   dst->set.mimepostp = NULL;
     884: #endif
     885:   /* clear all dest string and blob pointers first, in case we error out
     886:      mid-function */
     887:   memset(dst->set.str, 0, STRING_LAST * sizeof(char *));
     888:   memset(dst->set.blobs, 0, BLOB_LAST * sizeof(struct curl_blob *));
     889: 
     890:   /* duplicate all strings */
     891:   for(i = (enum dupstring)0; i < STRING_LASTZEROTERMINATED; i++) {
     892:     result = Curl_setstropt(&dst->set.str[i], src->set.str[i]);
     893:     if(result)
     894:       return result;
     895:   }
     896: 
     897:   /* duplicate all blobs */
     898:   for(j = (enum dupblob)0; j < BLOB_LAST; j++) {
     899:     result = Curl_setblobopt(&dst->set.blobs[j], src->set.blobs[j]);
     900:     if(result)
     901:       return result;
     902:   }
     903: 
     904:   /* duplicate memory areas pointed to */
     905:   i = STRING_COPYPOSTFIELDS;
     906:   if(src->set.str[i]) {
     907:     if(src->set.postfieldsize == -1)
     908:       dst->set.str[i] = curlx_strdup(src->set.str[i]);
     909:     else
     910:       /* postfieldsize is curl_off_t, curlx_memdup() takes a size_t ... */
     911:       dst->set.str[i] = curlx_memdup(src->set.str[i],
     912:                                      curlx_sotouz(src->set.postfieldsize));
     913:     if(!dst->set.str[i])
     914:       return CURLE_OUT_OF_MEMORY;
     915:     /* point to the new copy */
     916:     dst->set.postfields = dst->set.str[i];
     917:   }
     918: 
     919: #if !defined(CURL_DISABLE_MIME) || !defined(CURL_DISABLE_FORM_API)
     920:   if(src->set.mimepostp) {
     921:     /* Duplicate mime data. Get a mimepost struct for the clone as well */
>>   922:     dst->set.mimepostp = curlx_malloc(sizeof(*dst->set.mimepostp));
     923:     if(!dst->set.mimepostp)
     924:       return CURLE_OUT_OF_MEMORY;
     925: 
     926:     Curl_mime_initpart(dst->set.mimepostp);
     927:     result = Curl_mime_duppart(dst, dst->set.mimepostp, src->set.mimepostp);
     928:     if(result)
     929:       return result;
     930:   }
     931: #endif
     932: 
     933:   if(src->set.resolve)
     934:     dst->state.resolve = dst->set.resolve;
     935: 
     936:   return result;
     937: }

